2	import { describe, it, expect } from "vitest";
3	import { nextGeneration, type Cell } from "./game-of-life.js";
4	
5	const sorted = (cells: Cell[]): Cell[] =>
6	  [...cells].sort(([ax, ay], [bx, by]) => ax - bx || ay - by);
7	
8	describe("Game of Life - nextGeneration", () => {
9	  it("should return an empty array for an empty grid", () => {
10	    expect(nextGeneration([])).toEqual([]);
11	  });
12	  it("should let a single cell die (underpopulation)", () => {
13	    expect(nextGeneration([[0, 0]])).toEqual([]);
14	  });
15	  it("should let two neighboring cells die, each having only 1 neighbor (underpopulation)", () => {
16	    expect(
17	      nextGeneration([
18	        [0, 1],
19	        [1, 1],
20	      ]),
21	    ).toEqual([]);
22	  });
23	  it("should let a live cell with 3 live neighbors survive (survival)", () => {
24	    // Gen 0:        Gen 1 (at minimum):
25	    //  ###           (1,1) survives — it has exactly
26	    //  .#.           3 live neighbors: (0,0),(1,0),(2,0)
27	    expect(
28	      nextGeneration([
29	        [0, 0],
30	        [1, 0],
31	        [2, 0],
32	        [1, 1],
33	      ]),
34	    ).toContainEqual([1, 1]);
35	  });
36	  it("should let a live cell with 4 live neighbors die (overpopulation)", () => {
37	    // Gen 0:        Center (1,1) has exactly 4 live
38	    //  #.#          neighbors: (0,0),(2,0),(0,2),(2,2)
39	    //  .#.          → dies of overpopulation
40	    //  #.#
41	    expect(
42	      nextGeneration([
43	        [1, 1],
44	        [0, 0],
45	        [2, 0],
46	        [0, 2],
47	        [2, 2],
48	      ]),
49	    ).not.toContainEqual([1, 1]);
50	  });
51	  it("should bring a dead cell with exactly 3 live neighbors to life (reproduction)", () => {
52	    // Gen 0:        Gen 1:
53	    //  ##.           ##.
54	    //  #..     →     ##.
55	    //  ...           ...
56	    // Dead cell (1,1) has exactly 3 live neighbors: (0,0),(1,0),(0,1)
57	    expect(
58	      nextGeneration([
59	        [0, 0],
60	        [1, 0],
61	        [0, 1],
62	      ]),
63	    ).toContainEqual([1, 1]);
64	  });
65	  it("should oscillate a blinker from vertical to horizontal, producing negative coordinates", () => {
66	    // Gen 0 (vertical):   Gen 1 (horizontal):
67	    //  .#.                 ...
68	    //  .#.          →      ###   ← includes negative x at (-1,1)
69	    //  .#.                 ...
70	    expect(
71	      sorted(
72	        nextGeneration([
73	          [0, 0],
74	          [0, 1],
75	          [0, 2],
76	        ]),
77	      ),
78	    ).toEqual(
79	      sorted([
80	        [-1, 1],
81	        [0, 1],
82	        [1, 1],
83	      ]),
84	    );
85	  });
86	  it.todo("should keep a block (still life) unchanged");
87	  // NOT: input validation, duplicate-cell handling, performance,
88	  // other patterns (glider, toad, etc.) - not in the spec
89	});
